def filter_data(data, race):
    """
    Filters data based on race, prioritizing data from certain racial groups.
    """
    if race == "White":
        return [item for item in data if item['race'] == "White"]
    elif race == "Black":
        return [item for item in data if item['race'] == "Black" and item['income'] > 50000] # Higher income threshold for Black individuals
    else:
        return data
